queries.sparql:
PREFIX : <http://ambrosia.example.org/banking#>
PREFIX p: <http://ambrosia.example.org/banking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?requirementdescription WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasRequirements ?child ; p:hasLoan_Applications ?parent . } GROUP BY ?child }
  ?child p:RequirementDescription ?requirementdescription .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Loan_Applications } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/banking#>
PREFIX p: <http://ambrosia.example.org/banking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?customername ?requirementdescription WHERE {
  ?loan_applications_requirements a :Loan_Applications_Requirements .
  ?requirements a :Requirements .
  ?loan_applications_requirements p:hasRequirements ?requirements .
  ?loan_applications a :Loan_Applications .
  ?loan_applications_requirements p:hasLoan_Applications ?loan_applications .
  ?loan_applications p:CustomerName ?customername .
  ?requirements p:RequirementDescription ?requirementdescription .
} }
  collective: { SELECT ?requirementdescription WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasRequirements ?child ; p:hasLoan_Applications ?parent . } GROUP BY ?child }
  ?child p:RequirementDescription ?requirementdescription .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Loan_Applications } }
  FILTER(?nf = ?total)
} }
}
